def update_week(week):
    date = week["date"]
    payload = {}
    for field in ("ot_content", "psalm_content", "epistle_content", "gospel_content"):
        if field in week:
            payload[field] = week[field].strip()

    data = json.dumps(payload).encode("utf-8")
    req = urllib.request.Request(
        f"{URL}?sunday_date=eq.{date}",
        data=data,
        headers={
            "apikey": KEY,
            "Authorization": f"Bearer {KEY}",
            "Content-Type": "application/json",
            "Prefer": "return=minimal",
        },
        method="PATCH",
    )
    try:
        with urllib.request.urlopen(req) as res:
            print(f"✓ {date}  ({res.status})")
    except Exception as e:
        print(f"✗ {date}  {e}")

for week in WEEKS:
    update_week(week)

